(500057,2,'SpringBoot集成Redis - 基于RedisTemplate+Lettuce数据类封装','RedisTemplate中的操作和方法众多，为了程序保持方法使用的一致性，屏蔽一些无关的方法以及对使用的方法进一步封装。 PS：同样的类似思路也体现在很多场景中，比如Tomcat Request利用外观模式改造https://pdai.tech/md/framework/tomcat/tomcat-x-design-web-container.html%E5%88%A9%E7%94%A8%E5%A4%96%E8%A7%82%E6%A8%A1%E5%BC%8F%E6%94%B9%E9%80%A0...','# SpringBoot集成Redis - 基于RedisTemplate+Lettuce数据类封装\n\n> 前两篇文章介绍了SpringBoot基于RedisTemplate的数据操作，那么如何对这些操作进行封装呢？本文主要介绍基于RedisTemplate的封装。@pdai\n\n- SpringBoot集成Redis - 基于RedisTemplate+Lettuce数据类封装知识准备有了RedisTemplate为什么还要进一步封装？实现案例RedisService封装RedisService的调用示例源码\n\n## 知识准备\n\n> 需要对封装的场景有理解。@pdai\n\n### 有了RedisTemplate为什么还要进一步封装？\n\nRedisTemplate中的操作和方法众多，为了程序保持方法使用的一致性，屏蔽一些无关的方法以及对使用的方法进一步封装。\n\nPS：同样的类似思路也体现在很多场景中，比如[Tomcat Request利用外观模式改造](https://pdai.tech/md/framework/tomcat/tomcat-x-design-web-container.html#%E5%88%A9%E7%94%A8%E5%A4%96%E8%A7%82%E6%A8%A1%E5%BC%8F%E6%94%B9%E9%80%A0)。\n\n## 实现案例\n\n> 本文主要展示基于RedisTemplate的部分简单封装的示例。@pdai\n\n### RedisService封装\n\nRedisService接口类\n\n```\npackage tech.pdai.springboot.redis.lettuce.enclosure.service;\n\nimport org.springframework.data.redis.core.RedisCallback;\n\nimport java.util.Collection;\nimport java.util.Set;\n\n/**\n * Redis Service.\n *\n * @author pdai\n */\npublic interface IRedisService<T> {\n\n    void set(String key, T value);\n\n    void set(String key, T value, long time);\n\n    T get(String key);\n\n    void delete(String key);\n\n    void delete(Collection<String> keys);\n\n    boolean expire(String key, long time);\n\n    Long getExpire(String key);\n\n    boolean hasKey(String key);\n\n    Long increment(String key, long delta);\n\n    Long decrement(String key, long delta);\n\n    void addSet(String key, T value);\n\n    Set<T> getSet(String key);\n\n    void deleteSet(String key, T value);\n\n    T execute(RedisCallback<T> redisCallback);\n}\n```\n\nRedisService的实现类\n\n```\npackage tech.pdai.springboot.redis.lettuce.enclosure.service.impl;\n\nimport org.springframework.data.redis.core.RedisCallback;\nimport org.springframework.data.redis.core.RedisTemplate;\nimport org.springframework.stereotype.Service;\nimport tech.pdai.springboot.redis.lettuce.enclosure.service.IRedisService;\n\nimport javax.annotation.Resource;\nimport java.util.Collection;\nimport java.util.Set;\nimport java.util.concurrent.TimeUnit;\n\n/**\n * @author pdai\n */\n@Service\npublic class RedisServiceImpl<T> implements IRedisService<T> {\n\n    @Resource\n    private RedisTemplate<String, T> redisTemplate;\n\n    @Override\n    public void set(String key, T value, long time) {\n        redisTemplate.opsForValue().set(key, value, time, TimeUnit.SECONDS);\n    }\n\n    @Override\n    public void set(String key, T value) {\n        redisTemplate.opsForValue().set(key, value);\n    }\n\n    @Override\n    public T get(String key) {\n        return redisTemplate.opsForValue().get(key);\n    }\n\n    @Override\n    public void delete(String key) {\n        redisTemplate.delete(key);\n    }\n\n    @Override\n    public void delete(Collection<String> keys) {\n        redisTemplate.delete(keys);\n    }\n\n    @Override\n    public boolean expire(String key, long time) {\n        return redisTemplate.expire(key, time, TimeUnit.SECONDS);\n    }\n\n    @Override\n    public Long getExpire(String key) {\n        return redisTemplate.getExpire(key, TimeUnit.SECONDS);\n    }\n\n    @Override\n    public boolean hasKey(String key) {\n        return redisTemplate.hasKey(key);\n    }\n\n    @Override\n    public Long increment(String key, long delta) {\n        return redisTemplate.opsForValue().increment(key, delta);\n    }\n\n    @Override\n    public Long decrement(String key, long delta) {\n        return redisTemplate.opsForValue().increment(key, -delta);\n    }\n\n    @Override\n    public void addSet(String key, T value) {\n        redisTemplate.opsForSet().add(key, value);\n    }\n\n    @Override\n    public Set<T> getSet(String key) {\n        return redisTemplate.opsForSet().members(key);\n    }\n\n    @Override\n    public void deleteSet(String key, T value) {\n        redisTemplate.opsForSet().remove(key, value);\n    }\n\n    @Override\n    public T execute(RedisCallback<T> redisCallback) {\n        return redisTemplate.execute(redisCallback);\n    }\n\n}\n```\n\n### RedisService的调用\n\nUserController类中调用RedisService\n\n```\npackage tech.pdai.springboot.redis.lettuce.enclosure.controller;\n\nimport io.swagger.annotations.ApiOperation;\nimport org.springframework.beans.factory.annotation.Autowired;\nimport org.springframework.web.bind.annotation.GetMapping;\nimport org.springframework.web.bind.annotation.PathVariable;\nimport org.springframework.web.bind.annotation.PostMapping;\nimport org.springframework.web.bind.annotation.RequestMapping;\nimport org.springframework.web.bind.annotation.RestController;\nimport tech.pdai.springboot.redis.lettuce.enclosure.entity.User;\nimport tech.pdai.springboot.redis.lettuce.enclosure.entity.response.ResponseResult;\nimport tech.pdai.springboot.redis.lettuce.enclosure.service.IRedisService;\n\n/**\n * @author pdai\n */\n@RestController\n@RequestMapping("/user")\npublic class UserController {\n\n    @Autowired\n    private IRedisService<User> redisService;\n\n    /**\n     * @param user user param\n     * @return user\n     */\n    @ApiOperation("Add")\n    @PostMapping("add")\n    public ResponseResult<User> add(User user) {\n        redisService.set(String.valueOf(user.getId()), user);\n        return ResponseResult.success(redisService.get(String.valueOf(user.getId())));\n    }\n\n    /**\n     * @return user list\n     */\n    @ApiOperation("Find")\n    @GetMapping("find/{userId}")\n    public ResponseResult<User> edit(@PathVariable("userId") String userId) {\n        return ResponseResult.success(redisService.get(userId));\n    }\n\n}\n```\n\n## 示例源码\n\nhttps://github.com/realpdai/tech-pdai-spring-demos\n\n---\n\n原文链接：https://pdai.tech/md/spring/springboot/springboot-x-redis-lettuce-wrap.html','https://images.unsplash.com/photo-1550439062-609e1531270e?w=800','SpringBoot 2.5.x系列',NULL,0,NULL,'pdai-spring-springboot-springboot-x-redis-lettuce-wrap','SpringBoot集成Redis - 基于RedisTemplate+Lettuce数据类封装 - 技术博客','RedisTemplate中的操作和方法众多，为了程序保持方法使用的一致性，屏蔽一些无关的方法以及对使用的方法进一步封装。 PS：同样的类似思路也体现在很多场景中，比如Tomcat Request利用外观模式改造https://pdai.t...',0,'PUBLISHED',2339,261,180,7,'2025-09-23 00:00:00','2025-09-23 00:00:00','2026-05-08 23:34:42',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`view_count`=VALUES(`view_count`),`like_count`=VALUES(`like_count`),`favorite_count`=VALUES(`favorite_count`),`comment_count`=VALUES(`comment_count`),`published_at`=VALUES(`published_at`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
