(500091,2,'▶SpringBoot进阶 - 实现自动装配原理','暂无摘要','## ▶SpringBoot进阶 - 实现自动装配原理\n\n> 内容获取失败，请访问原文：https://pdai.tech/md/spring/springboot/springboot-y-auo-config.html\n','https://images.unsplash.com/photo-1607798748738-b15c40d33d57?w=800','SpringBoot 2.5.x系列',NULL,0,NULL,'pdai-spring-springboot-springboot-y-auo-config','▶SpringBoot进阶 - 实现自动装配原理 - 技术博客','暂无摘要',0,'PUBLISHED',5183,25,348,99,'2025-11-30 00:00:00','2025-11-30 00:00:00','2026-05-08 23:34:42',NULL,0) ON DUPLICATE KEY UPDATE `author_id`=VALUES(`author_id`),`title`=VALUES(`title`),`summary`=VALUES(`summary`),`content`=VALUES(`content`),`cover_url`=VALUES(`cover_url`),`category`=VALUES(`category`),`offline_reason`=VALUES(`offline_reason`),`featured`=VALUES(`featured`),`featured_at`=VALUES(`featured_at`),`seo_title`=VALUES(`seo_title`),`seo_description`=VALUES(`seo_description`),`warn_flag`=VALUES(`warn_flag`),`status`=VALUES(`status`),`view_count`=VALUES(`view_count`),`like_count`=VALUES(`like_count`),`favorite_count`=VALUES(`favorite_count`),`comment_count`=VALUES(`comment_count`),`published_at`=VALUES(`published_at`),`updated_at`=VALUES(`updated_at`),`deleted_at`=NULL;
