UPDATE `blog_tag` t SET `use_count` = (SELECT COUNT(*) FROM `blog_article_tag` atg WHERE atg.`tag_name` = t.`name` AND atg.`deleted_at` IS NULL) WHERE t.`name` IN ('Docker', 'ElasticSearch', 'IO', 'Linux', 'MongoDB', 'MySQL', 'Redis', 'Spring', 'Spring Boot', 'Spring Framework 5基础', 'SpringBoot 2.5.x系列', '并发编程', '异常', '架构设计', '注解', '源码解析', '线程池');

UPDATE `blog_column` c SET `article_count` = (SELECT COUNT(*) FROM `blog_column_article` ca INNER JOIN `blog_article` a ON a.`id` = ca.`article_id` WHERE ca.`column_id` = c.`id` AND ca.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE c.`id` IN (9200005);

UPDATE `blog_topic` t SET `article_count` = (SELECT COUNT(*) FROM `blog_topic_article` ta INNER JOIN `blog_article` a ON a.`id` = ta.`article_id` WHERE ta.`topic_id` = t.`id` AND ta.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE t.`id` IN (9305001, 9305002);

